  ('disabled-6f0ba476-moex-00081', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲女之弟為乙男，乙妻為丙。丙之父為丁、丁之妹為戊。下列關於親屬 關係之敘述，何者正確？', '["丁與甲為二親等旁系姻親", "丙與戊為三親等旁系血親", "乙與丁為二親等直系姻親", "戊與丁為三親等旁系血親"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00082', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '關於夫妻剩餘財產分配請求權之計算，下列夫或妻之一方所為之清償， 除已補償者外，何者應納入現存之婚後財產計算？', '["以其婚後財產清償其婚前所負之債務", "以其婚前財產清償婚姻關係存續中所負之債務", "以其慰撫金清償婚姻關係存續中所負之債務", "以其繼承財產清償婚姻關係存續中所負之債務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00083', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '依民法第1177條、第1178條規定，繼承開始時，繼承人之有無不明者， 法院應於親屬會議選定遺產管理人後進行何種程序？', '["公示催告", "遺產信託", "選定遺產執行人", "選定監護人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00084', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲欲自立遺囑，有關遺囑之撤回，下列何者不生撤回之效力？', '["甲完成一份自書遺囑後，內容載明現金新臺幣 600 萬元，平均分配於 3位繼承人，日後另於隨身手冊記載僅分配於其中2人", "甲完成一份自書遺囑，數日後，在該遺囑記載：廢棄", "甲完成一份自書遺囑載明遺產平均分配於 3 位繼承人，嗣後又依法完 成另一份遺囑並記載僅分配於其中2人", "甲完成一份自書遺囑載明遺贈A屋於好友乙，數日後，卻把該屋贈送 另一好友丙"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00085', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲喪妻，另有乙、丙二子。乙有丁、戊二子。甲於乙結婚時，贈與乙價 值新臺幣（下同）400萬元之房地一筆。乙於民國（下同）105年間死亡。 嗣甲於113年間死亡時，留有遺產2,000萬元。下列敘述何者正確？', '["甲之應繼遺產為2,000萬元，由丙單獨繼承", "甲之應繼遺產為2,000萬元，由丙繼承1,000萬元，丁繼承500萬元， 戊繼承500萬元", "甲之應繼遺產為2,400萬元，由丙、丁、戊各繼承800萬元", "甲之應繼遺產為2,400萬元，由丙繼承1,200萬元，丁繼承400萬元， 戊繼承400萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00086', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'essay', '請依據我國現行房屋稅條例之規定，回答下列問題：
依據「住家用房屋供自住及公益出租人出租使用認定標準」，個人
自住得適用住家用房屋稅率之條件為何？（9分）
非住家用房屋：供營業、私人醫院、診所或自由職業事務所使用者，
其稅率為何？（3 分）
試說明低現值住家用房屋欲適用免徵房屋稅之條件為何？（6分）
現行所謂的囤房稅 2.0 將納稅義務人之全國房屋如何分類與計算每
一戶適用之稅率？試說明之。（7 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00087', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'essay', '老王欲出售未上市櫃甲公司股票，該股權是老王於民國 90 年購入，
目前老王持股 40%，老王的兒子持股 20%，老王的弟弟持股 40%。
甲公司股權價值中有60%是由甲公司持有的我國境內不動產所構成，
該不動產是甲公司於民國92 年購入的房地一筆，試回答下列問題：
若老王只出售 10%的股票應如何課稅？法令依據為何？並請說明
適用稅率是多少？（15 分）
承題，若甲公司持有的不動產價值只占股權的 20%，則老王出售
10%持股應如何課稅？（5 分）
若把題目改為老王持有甲公司是上市股票，其餘不變，則老王出售
10%持股應如何課稅？（5 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00088', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', '我國對於稅捐稽徵之規定，下列敘述何者錯誤？', '["政府租稅之徵收應優先於普通債權", "土地增值稅、地價稅、所得稅之徵收及法院、法務部行政執行署所屬行 政執行分署執行拍賣或變賣貨物應課徵之營業稅，優先於一切債權及抵 押權", "納稅義務人如發現繳納通知文書有記載、計算錯誤或重複時，於規定繳 納期間內，得要求稅捐稽徵機關，查對更正", "非因不可抗力或不可歸責於納稅義務人之事由，而逾稅法規定期限繳納 稅捐者，應加徵滯納金，每逾3日按滯納數額加徵百分之一滯納金；逾 30日仍未繳納者，移送強制執行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00089', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', '某甲於民國 113 年 5 月 15 日完成 112 年度綜合所得稅結算申報，依稅捐 稽徵法之規定，其核課期間應自何時起算？', '["113年5月1日", "113年5月15日", "113年5月16日", "113年5月31日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00090', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', '依納稅者權利保護法規定，關於租稅規避行為，下列敘述何者錯誤？', '["租稅規避應按實質上經濟利益相當之法律形式課稅", "租稅規避係濫用法律形式的行為", "稅捐稽徴機關得就補繳稅款加徵25%滯納金", "稅捐稽徵機關應就租稅規避要件事實負擔舉證責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
